"""
This module represents the checkers board.
"""

class Board:
    def __init__(self):
        self.grid = self._initialize_board()

    def _initialize_board(self):
        grid = [[' ' for _ in range(8)] for _ in range(8)]
        # Place initial pieces for red
        for i in range(3):
            for j in (1, 3, 5, 7):
                if (i + j) % 2 == 0:
                    grid[i][j] = 'R'
        # Place initial pieces for black
        for i in range(5, 8):
            for j in (0, 2, 4, 6):
                if (i - j) % 2 == 0:
                    grid[i][j] = 'B'
        return grid

    def display(self):
        print("  a b c d e f g h")
        for i, row in enumerate(self.grid, start=1):
            print(f"{i} {' '.join(row)}")

    def move(self, from_pos, to_pos):
        x_from, y_from = from_pos
        x_to, y_to = to_pos
        piece = self.grid[x_from][y_from]
        if (x_to - x_from) == 2 and abs(y_to - y_from) == 2:
            # Capture move
            jump_over_x, jump_over_y = (from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2
            if self.grid[jump_over_x][jump_over_y] != piece.swapcase():
                return False
            self.grid[jump_over_x][jump_over_y] = ' '
        self.grid[x_to][y_to] = piece
        self.grid[x_from][y_from] = ' '
        return True

    def capture(self, from_pos, jump_over, to_pos):
        # This method is not implemented yet for simplicity
        pass

    def king(self, position):
        x, y = position
        if (x == 0 and self.grid[x][y] == 'R') or (x == 7 and self.grid[x][y] == 'B'):
            self.grid[x][y] = 'R' if piece == 'r' else 'B'
